// Validate webhook payload and build orientation checklist
const body = $input.first().json.body || $input.first().json;

const requiredFields = ['member_name', 'facility', 'bargaining_unit', 'hire_date'];
const missing = requiredFields.filter(f => !body[f]);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Predefined orientation checklist
const checklistItems = [
  {
    title: `Welcome packet: Prepare and send welcome materials for ${body.member_name}`,
    priority: 'high',
    due_offset_days: 1
  },
  {
    title: `Union orientation meeting: Schedule for ${body.member_name} at ${body.facility}`,
    priority: 'high',
    due_offset_days: 3
  },
  {
    title: `Contract copy: Provide ${body.bargaining_unit} contract to ${body.member_name}`,
    priority: 'high',
    due_offset_days: 3
  },
  {
    title: `Steward introduction: Connect ${body.member_name} with ${body.facility} steward`,
    priority: 'medium',
    due_offset_days: 5
  },
  {
    title: `Benefits overview: Review health, pension, and other benefits with ${body.member_name}`,
    priority: 'medium',
    due_offset_days: 7
  },
  {
    title: `Dues authorization: Collect signed dues authorization card from ${body.member_name}`,
    priority: 'high',
    due_offset_days: 7
  },
  {
    title: `Grievance rights: Explain grievance process and Weingarten rights to ${body.member_name}`,
    priority: 'medium',
    due_offset_days: 10
  },
  {
    title: `Committee opportunities: Discuss available committee roles with ${body.member_name}`,
    priority: 'low',
    due_offset_days: 14
  }
];

const hireDate = new Date(body.hire_date);
const tasks = checklistItems.map(item => {
  const dueDate = new Date(hireDate);
  dueDate.setDate(dueDate.getDate() + item.due_offset_days);
  return {
    json: {
      title: item.title,
      priority: item.priority,
      due_date: dueDate.toISOString().split('T')[0],
      assigned_to: 'execsec',
      tag: 'orientation',
      member_name: body.member_name,
      facility: body.facility,
      bargaining_unit: body.bargaining_unit,
      hire_date: body.hire_date
    }
  };
});

return tasks;

